  const authRequest = consumePendingAuthRequest(request_id);
  if (!authRequest) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Authorization request expired or invalid'
    });
  }

  // Validate input
  if (!username || typeof username !== 'string' || username.length > 128) {
    return renderLoginError(res, authRequest, 'Invalid username');
  }

  if (!password || typeof password !== 'string' || password.length > 256) {
    return renderLoginError(res, authRequest, 'Invalid password');
  }

  // Sanitize username for lookup
