function issueAuthorizationCode(res, userId, clientId, redirectUri, state, scope, codeChallenge, codeChallengeMethod) {
  const code = generateAuthorizationCode();

  authorizationCodes.set(code, {
    userId,
    clientId,
    redirectUri,
    scope: scope || '',
    codeChallenge,
    codeChallengeMethod,
    createdAt: Date.now(),
    expiresAt: Date.now() + 60 * 1000, // 1 minute expiry (short-lived)
    used: false
  });

  const redirectUrl = new URL(redirectUri);
  redirectUrl.searchParams.set('code', code);
  redirectUrl.searchParams.set('state', state);

  res.setHeader('Cache-Control', 'no-store');
  res.setHeader('Pragma', 'no-cache');
  res.redirect(302, redirectUrl.toString());
}

function redirectWithError(res, redirectUri, error, errorDescription, state) {
  const redirectUrl = new URL(redirectUri);
  redirectUrl.searchParams.set('error', error);
  redirectUrl.searchParams.set('error_description', errorDescription);
  if (state) {
    redirectUrl.searchParams.set('state', state);
  }

  res.setHeader('Cache-Control', 'no-store');
  res.setHeader('Pragma', 'no-cache');
  res.redirect(302, redirectUrl.toString());
}

